import React, { createContext, useContext, useState } from "react";
import CryptoJS from "crypto-js";
const initialData = {
    isAuthenticated: false,
    login: () => { },
    logout: () => { }
};
const AuthContext = createContext(initialData);
const encryptData = (data) => {
    return CryptoJS.AES.encrypt(data, process.env.SECRET_KEY).toString();
};
const decryptData = (ciphertext) => {
    const bytes = CryptoJS.AES.decrypt(ciphertext, process.env.SECRET_KEY);
    return bytes.toString(CryptoJS.enc.Utf8);
};
const AuthContextProvider = ({ children }) => {
    const token = decryptData(sessionStorage.getItem("token") || "");
    const [isAuthenticated, setIsAuthenticated] = useState(token === `${process.env.USER_NAME}-${process.env.PASSWORD}`);
    const login = (username, password) => {
        if (username.trim().toLowerCase() === process.env.USER_NAME
            && password === process.env.PASSWORD) {
            const newToken = encryptData(`${process.env.USER_NAME}-${process.env.PASSWORD}`);
            sessionStorage.setItem("token", newToken);
            setIsAuthenticated(true);
        }
    };
    const logout = () => {
        sessionStorage.removeItem("token");
        setIsAuthenticated(false);
    };
    return (React.createElement(AuthContext.Provider, { value: { isAuthenticated, login, logout } }, children));
};
const useAuth = () => useContext(AuthContext);
export { AuthContextProvider, useAuth };
