import React, { createContext, useContext, useState, useEffect } from "react";
import { useFilters } from "../Filters";
import loadChecks from "../../utils/loadChecks";
import { filterByDateRange } from "../../utils/filterByDateRange";
import { getEarliestReceip } from "../../utils/getEarliestReceip";
import { getQuerySearchRe } from "../../constants/regexes";
const initialData = {
    receipts: [],
    earliestReceip: null,
    isLoading: true
};
