// @ts-ignore
const receiptsImgs = require.context(process.env.PATH_TO_RECEIPTS_IMAGES, false, /\.(png|jpe?g|gif|svg)$/);
function getImagesDateToPathMap() {
    return receiptsImgs.keys().reduce((map, key) => {
        const fileName = key.replace("./", "").replace(/\.(jpe?g)|png/, "");
        map[fileName] = receiptsImgs(key);
        return map;
    }, {});
}
export const imagesDateToPathMap = getImagesDateToPathMap();
