export const SHOPS_RE = /(mercadona|carrefour)/im;
export const DATE_RE = /(\d\d\/\d\d\/\d\d\d\d)/im;
export const TIME_RE = /(\d\d\:\d\d)/im;
export const DESCRIPTION_WORD_RE = /(\bdescripti(o|ó)n\b|descr([a-z\s])+i(o|ó)n)/im;
export const TOTAL_WORD_RE = /\b(total)\b/im;
export const TOTAL_SUMM_RE = /(\d{1,3}(\,|\.)\d\d)/im;
const diacriticsMap = {
    "a": "(a|á)", // (a|á|à|â|ä|ã|å|ā)
    "o": "(o|ó)", // oóòôöõøō
    "e": "(e|é)", // eéèêëē
    "i": "(i|í)", // iíìîïī
    "u": "(u|ú)", // uúùûüū
    "n": "(n|ñ)"
};
const replaceAllDiacriticsChars = (query) => {
    const diacriticsKeys = Object.keys(diacriticsMap);
    let result = query.toLowerCase();
    diacriticsKeys.forEach((key) => {
        result = result.replaceAll(key, `${diacriticsMap[key].replace("(", "(?:")}`);
    });
    return result;
};
export const getQuerySearchRe = (query) => {
    return new RegExp(`(${replaceAllDiacriticsChars(query)})`, "giu");
};
